import { useState, useRef, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import { FiArrowLeft } from "react-icons/fi";
import "./styles.css";

export default function EmailVerify() {
  const navigate = useNavigate();
  const inputs = useRef([]);

  const [otp, setOtp] = useState(["", "", "", "", "", ""]);
  const [time, setTime] = useState(45);

  // TIMER
  useEffect(() => {
    if (time === 0) return;
    const timer = setInterval(() => setTime((t) => t - 1), 1000);
    return () => clearInterval(timer);
  }, [time]);

  const handleChange = (val, i) => {
    if (!/^\d*$/.test(val)) return;

    const updated = [...otp];
    updated[i] = val.slice(-1);
    setOtp(updated);

    if (val && i < 5) inputs.current[i + 1].focus();
  };

  const handleBackspace = (e, i) => {
    if (e.key === "Backspace" && !otp[i] && i > 0) {
      inputs.current[i - 1].focus();
    }
  };

  const handlePaste = (e) => {
    const pasted = e.clipboardData.getData("text").slice(0, 6);
    if (!/^\d+$/.test(pasted)) return;

    const newOtp = pasted.split("");
    setOtp([...newOtp, ...Array(6 - newOtp.length).fill("")]);

    newOtp.forEach((val, i) => {
      inputs.current[i].value = val;
    });
  };

  const handleVerify = () => {
    if (otp.join("") === "123456") {
      navigate("/success", { state: { type: "email" } });
    } else {
      alert("Invalid Code");
    }
  };

  return (
    <div className="email-wrapper">

      {/* LEFT PANEL */}
      <div className="email-left">
        <div className="logo">LOS</div>

        <h1>Verify your email</h1>
        <p>
          Please enter the 6-digit verification code sent to your email address
          to complete the authentication process.
        </p>
      </div>

      {/* RIGHT PANEL */}
      <div className="email-right">

        <div className="email-card">

          <div className="back" onClick={() => navigate(-1)}>
            <FiArrowLeft />
          </div>

          <h2>Email Verification</h2>

          <p className="subtext">
            We’ve sent a 6-digit code to <br />
            <span className="email-text">yourmail@example.com</span>
          </p>

          <div className="otp-box" onPaste={handlePaste}>
            {otp.map((d, i) => (
              <input
                key={i}
                ref={(el) => (inputs.current[i] = el)}
                value={d}
                onChange={(e) => handleChange(e.target.value, i)}
                onKeyDown={(e) => handleBackspace(e, i)}
                maxLength={1}
              />
            ))}
          </div>

          <p className="resend">
            Resend code in{" "}
            <span>
              00:{time.toString().padStart(2, "0")}
            </span>
          </p>

          <button
            className="purple-btn"
            disabled={otp.join("").length !== 6}
            onClick={handleVerify}
          >
            Verify Code
          </button>

        </div>

      </div>
    </div>
  );
}
